using UnityEngine;
using System;

public class PlayerStats : MonoBehaviour
{
    [Header("Player Stats")]
    public int maxHealth = 100;
    public int currentHealth = 100;
    public int currency = 500;
    public int baseDamage = 10;
    public int bonusDamage = 0;

    public event Action<int, int> OnHealthChanged;
    public event Action<int> OnCurrencyChanged;

    private void Awake()
    {
        currentHealth = Mathf.Clamp(currentHealth, 0, maxHealth);
        NotifyHealth();
        NotifyCurrency();
    }

    public int GetTotalDamage()
    {
        return baseDamage + bonusDamage;
    }

    public void TakeDamage(int incomingDamage, int armor = 0)
    {
        int finalDamage = CalculateDamageTaken(incomingDamage, armor);
        currentHealth = Mathf.Max(0, currentHealth - finalDamage);
        NotifyHealth();
    }

    public void Heal(int amount)
    {
        currentHealth = Mathf.Min(maxHealth, currentHealth + Mathf.Max(0, amount));
        NotifyHealth();
    }

    public bool SpendCurrency(int amount)
    {
        if (amount < 0) return false;
        if (currency < amount) return false;

        currency -= amount;
        NotifyCurrency();
        return true;
    }

    public void AddCurrency(int amount)
    {
        if (amount <= 0) return;
        currency += amount;
        NotifyCurrency();
    }

    public int CalculateDamageDealt(float multiplier = 1f)
    {
        return Mathf.Max(0, Mathf.RoundToInt(GetTotalDamage() * multiplier));
    }

    public int CalculateDamageTaken(int incomingDamage, int armor = 0)
    {
        int reduced = incomingDamage - armor;
        return Mathf.Max(1, reduced);
    }

    private void NotifyHealth()
    {
        OnHealthChanged?.Invoke(currentHealth, maxHealth);
    }

    private void NotifyCurrency()
    {
        OnCurrencyChanged?.Invoke(currency);
    }
}

[Serializable]
public class ShopItem
{
    public string itemId;
    public string displayName;
    public int basePrice;
    public int priceIncreasePerPurchase;
    public int purchases;
    public int damageBonus;
    public int healthBonus;
    public bool consumable;

    public int GetCurrentPrice()
    {
        return Mathf.Max(0, basePrice + (priceIncreasePerPurchase * purchases));
    }
}

public class ShopSystem : MonoBehaviour
{
    [Header("References")]
    public PlayerStats playerStats;

    [Header("Shop Inventory")]
    public ShopItem[] items;

    public bool PurchaseItem(string itemId)
    {
        if (playerStats == null || items == null) return false;

        for (int i = 0; i < items.Length; i++)
        {
            if (items[i] != null && items[i].itemId == itemId)
            {
                return PurchaseItem(items[i]);
            }
        }

        return false;
    }

    public bool PurchaseItem(ShopItem item)
    {
        if (playerStats == null || item == null) return false;

        int price = item.GetCurrentPrice();
        if (!playerStats.SpendCurrency(price)) return false;

        ApplyItemEffects(item);

        if (!item.consumable)
        {
            item.purchases++;
        }

        return true;
    }

    public int GetItemPrice(string itemId)
    {
        if (items == null) return -1;

        for (int i = 0; i < items.Length; i++)
        {
            if (items[i] != null && items[i].itemId == itemId)
            {
                return items[i].GetCurrentPrice();
            }
        }

        return -1;
    }

    private void ApplyItemEffects(ShopItem item)
    {
        playerStats.bonusDamage += item.damageBonus;
        playerStats.maxHealth += item.healthBonus;
        playerStats.currentHealth = Mathf.Min(playerStats.currentHealth + item.healthBonus, playerStats.maxHealth);
    }
}

public class Enemy : MonoBehaviour
{
    public int maxHealth = 50;
    public int currentHealth = 50;
    public int armor = 2;
    public int contactDamage = 8;

    private void Awake()
    {
        currentHealth = Mathf.Clamp(currentHealth, 0, maxHealth);
    }

    public void TakeHit(PlayerStats attacker, float damageMultiplier = 1f)
    {
        if (attacker == null) return;

        int dealtDamage = attacker.CalculateDamageDealt(damageMultiplier);
        currentHealth -= Mathf.Max(1, dealtDamage - armor);

        if (currentHealth <= 0)
        {
            currentHealth = 0;
            Die(attacker);
        }
    }

    private void Die(PlayerStats attacker)
    {
        if (attacker != null)
        {
            attacker.AddCurrency(25);
        }

        gameObject.SetActive(false);
    }

    private void OnCollisionEnter(Collision collision)
    {
        PlayerStats player = collision.gameObject.GetComponent<PlayerStats>();
        if (player != null)
        {
            player.TakeDamage(contactDamage);
        }
    }

    private void OnTriggerEnter(Collider other)
    {
        PlayerStats player = other.GetComponent<PlayerStats>();
        if (player != null)
        {
            player.TakeDamage(contactDamage);
        }
    }
}